// OT Utilities for frontend
const OTUtils = {
  createOperationFromChange: change => {
    if (change.rangeLength > 0) {
      return {
        type: 'delete',
        position: change.rangeOffset,
        length: change.rangeLength
      };
    } else if (change.text) {
      return {
        type: 'insert',
        position: change.rangeOffset,
        text: change.text
      };
    }
    return null;
  },
  applyOperationToEditor: (editor, operation) => {
    if (!editor || !operation) return;
    try {
      if (operation.type === 'insert') {
        const position = editor.getModel().getPositionAt(operation.position);
        editor.executeEdits('remote', [{
          range: new window.monaco.Range(position.lineNumber, position.column, position.lineNumber, position.column),
          text: operation.text,
          forceMoveMarkers: true
        }]);
      } else if (operation.type === 'delete') {
        const startPos = editor.getModel().getPositionAt(operation.position);
        const endPos = editor.getModel().getPositionAt(operation.position + operation.length);
        editor.executeEdits('remote', [{
          range: new window.monaco.Range(startPos.lineNumber, startPos.column, endPos.lineNumber, endPos.column),
          text: '',
          forceMoveMarkers: true
        }]);
      }
    } catch (error) {
      console.error('Error applying operation:', error);
    }
  }
};

