import React, { useState, useEffect, useRef } from 'react';
import io from 'socket.io-client';
import Editor from '@monaco-editor/react';
import { ToastContainer, toast } from 'react-toastify';
import 'react-toastify/dist/ReactToastify.css';
import axios from 'axios';
import { 
  Users, 
  Code2, 
  Bot, 
  Play, 
  Share2, 
  Sparkles,
  AlertTriangle,
  CheckCircle,
  UserPlus,
  LogIn,
  X,
  ArrowLeft,
  ChevronDown,
  RefreshCw,
  Terminal,
  Copy,
  Download
} from 'lucide-react';
import './App.css';

// Initialize socket with better connection options
const socket = io('http://localhost:5000', {
  transports: ['websocket', 'polling'],
  reconnection: true,
  reconnectionAttempts: 5,
  reconnectionDelay: 1000,
});

// Supported languages for dropdown
const LANGUAGE_OPTIONS = [
  { id: 'javascript', name: 'JavaScript', extension: 'js' },
  { id: 'python', name: 'Python', extension: 'py' },
  { id: 'java', name: 'Java', extension: 'java' },
  { id: 'cpp', name: 'C++', extension: 'cpp' },
  { id: 'c', name: 'C', extension: 'c' },
  { id: 'csharp', name: 'C#', extension: 'cs' },
  { id: 'php', name: 'PHP', extension: 'php' },
  { id: 'ruby', name: 'Ruby', extension: 'rb' },
  { id: 'go', name: 'Go', extension: 'go' },
  { id: 'rust', name: 'Rust', extension: 'rs' },
  { id: 'typescript', name: 'TypeScript', extension: 'ts' },
  { id: 'html', name: 'HTML', extension: 'html' },
  { id: 'css', name: 'CSS', extension: 'css' },
  { id: 'sql', name: 'SQL', extension: 'sql' }
];

// Default code templates for each language
const DEFAULT_CODE = {
  javascript: `// Welcome to Unified IDE - JavaScript Mode
// Start coding with your team...

function helloWorld() {
  console.log("Hello, Collaborative Coding!");
}

// Calculate factorial
function factorial(n) {
  if (n <= 1) return 1;
  return n * factorial(n - 1);
}`,

  python: `# Welcome to Unified IDE - Python Mode
# Start coding with your team...

def hello_world():
    print("Hello, Collaborative Coding!")

# Calculate factorial
def factorial(n):
    if n <= 1:
        return 1
    return n * factorial(n - 1)`,

  java: `// Welcome to Unified IDE - Java Mode
// Start coding with your team...

public class Main {
    public static void main(String[] args) {
        System.out.println("Hello, Collaborative Coding!");
    }
    
    // Calculate factorial
    public static int factorial(int n) {
        if (n <= 1) return 1;
        return n * factorial(n - 1);
    }
}`,

  cpp: `// Welcome to Unified IDE - C++ Mode
// Start coding with your team...

#include <iostream>
using namespace std;

// Calculate factorial
int factorial(int n) {
    if (n <= 1) return 1;
    return n * factorial(n - 1);
}

int main() {
    cout << "Hello, Collaborative Coding!" << endl;
    return 0;
}`,

  c: `// Welcome to Unified IDE - C Mode
// Start coding with your team...

#include <stdio.h>

// Calculate factorial
int factorial(int n) {
    if (n <= 1) return 1;
    return n * factorial(n - 1);
}

int main() {
    printf("Hello, Collaborative Coding!\\n");
    return 0;
}`,

  csharp: `// Welcome to Unified IDE - C# Mode
// Start coding with your team...

using System;

class Program {
    static void Main() {
        Console.WriteLine("Hello, Collaborative Coding!");
    }
    
    // Calculate factorial
    static int Factorial(int n) {
        if (n <= 1) return 1;
        return n * Factorial(n - 1);
    }
}`,

  php: `<?php
// Welcome to Unified IDE - PHP Mode
// Start coding with your team...

function helloWorld() {
    echo "Hello, Collaborative Coding!";
}

// Calculate factorial
function factorial($n) {
    if ($n <= 1) return 1;
    return $n * factorial($n - 1);
}

helloWorld();
?>`,

  ruby: `# Welcome to Unified IDE - Ruby Mode
# Start coding with your team...

def hello_world
  puts "Hello, Collaborative Coding!"
end

# Calculate factorial
def factorial(n)
  return 1 if n <= 1
  n * factorial(n - 1)
end

hello_world`,

  go: `// Welcome to Unified IDE - Go Mode
// Start coding with your team...

package main

import "fmt"

// Calculate factorial
func factorial(n int) int {
    if n <= 1 {
        return 1
    }
    return n * factorial(n-1)
}

func main() {
    fmt.Println("Hello, Collaborative Coding!")
}`,

  rust: `// Welcome to Unified IDE - Rust Mode
// Start coding with your team...

fn main() {
    println!("Hello, Collaborative Coding!");
}

// Calculate factorial
fn factorial(n: u64) -> u64 {
    if n <= 1 {
        1
    } else {
        n * factorial(n - 1)
    }
}`,

  typescript: `// Welcome to Unified IDE - TypeScript Mode
// Start coding with your team...

function helloWorld(): void {
    console.log("Hello, Collaborative Coding!");
}

// Calculate factorial
function factorial(n: number): number {
    if (n <= 1) return 1;
    return n * factorial(n - 1);
}`,

  html: `<!-- Welcome to Unified IDE - HTML Mode -->
<!-- Start coding with your team... -->

<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Collaborative Coding</title>
    <style>
        body {
            font-family: Arial, sans-serif;
            margin: 40px;
        }
    </style>
</head>
<body>
    <h1>Hello, Collaborative Coding!</h1>
    <p>Welcome to our real-time coding environment.</p>
</body>
</html>`,

  css: `/* Welcome to Unified IDE - CSS Mode */
/* Start coding with your team... */

body {
    font-family: 'Arial', sans-serif;
    margin: 0;
    padding: 0;
    background-color: #f5f5f5;
    color: #333;
}

.container {
    max-width: 1200px;
    margin: 0 auto;
    padding: 20px;
}

.header {
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    color: white;
    padding: 2rem;
    text-align: center;
}`,

  sql: `-- Welcome to Unified IDE - SQL Mode
-- Start coding with your team...

-- Create users table
CREATE TABLE users (
    id INT PRIMARY KEY AUTO_INCREMENT,
    username VARCHAR(50) NOT NULL UNIQUE,
    email VARCHAR(100) NOT NULL UNIQUE,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- Insert sample data
INSERT INTO users (username, email) VALUES 
('john_doe', 'john@example.com'),
('jane_smith', 'jane@example.com');

-- Select all users
SELECT * FROM users;`
};

// OT Utilities for frontend
const OTUtils = {
  createOperationFromChange: (change) => {
    if (change.rangeLength > 0) {
      return {
        type: 'delete',
        position: change.rangeOffset,
        length: change.rangeLength
      };
    } else if (change.text) {
      return {
        type: 'insert',
        position: change.rangeOffset,
        text: change.text
      };
    }
    return null;
  },

  applyOperationToEditor: (editor, operation) => {
    if (!editor || !operation) return;
    
    try {
      if (operation.type === 'insert') {
        const position = editor.getModel().getPositionAt(operation.position);
        editor.executeEdits('remote', [{
          range: new window.monaco.Range(
            position.lineNumber,
            position.column,
            position.lineNumber,
            position.column
          ),
          text: operation.text,
          forceMoveMarkers: true
        }]);
      } else if (operation.type === 'delete') {
        const startPos = editor.getModel().getPositionAt(operation.position);
        const endPos = editor.getModel().getPositionAt(operation.position + operation.length);
        editor.executeEdits('remote', [{
          range: new window.monaco.Range(
            startPos.lineNumber,
            startPos.column,
            endPos.lineNumber,
            endPos.column
          ),
          text: '',
          forceMoveMarkers: true
        }]);
      }
    } catch (error) {
      console.error('Error applying operation:', error);
    }
  }
};

// Main Login Options Component
function LoginOptions({ onSelectOption }) {
  const handleClearCache = () => {
    localStorage.clear();
    toast.success('Cache cleared! Refresh the page.');
  };

  return (
    <div className="login-container">
      <div className="login-card">
        <div className="login-header">
          <Code2 className="login-logo" />
          <h1>Unified IDE</h1>
          <p>Multi-language Collaborative Coding Platform</p>
          <button 
            onClick={handleClearCache} 
            className="btn btn-secondary btn-sm"
            style={{ marginTop: '10px', fontSize: '12px', padding: '6px 12px' }}
          >
            Clear Cache
          </button>
        </div>

        <div className="options-container">
          <div className="option-card" onClick={() => onSelectOption('create')}>
            <UserPlus className="option-icon" />
            <h3>Create Room</h3>
            <p>Start a new collaborative coding session</p>
            <div className="option-features">
              <span>• Generate unique room code</span>
              <span>• Invite team members</span>
              <span>• AI-powered assistance</span>
            </div>
          </div>

          <div className="option-card" onClick={() => onSelectOption('join')}>
            <LogIn className="option-icon" />
            <h3>Join Room</h3>
            <p>Enter an existing room with code</p>
            <div className="option-features">
              <span>• Join with room code</span>
              <span>• Real-time collaboration</span>
              <span>• Professional code editor</span>
            </div>
          </div>
        </div>

        <div className="login-features">
          <div className="feature">
            <Users className="feature-icon" />
            <span>Real-time Collaboration (Operational Transform)</span>
          </div>
          <div className="feature">
            <Bot className="feature-icon" />
            <span>AI-Powered Multi-language Support (15+ Languages)</span>
          </div>
          <div className="feature">
            <Terminal className="feature-icon" />
            <span>Integrated Terminal & Code Execution</span>
          </div>
        </div>
      </div>
    </div>
  );
}

// Create Room Component
function CreateRoom({ onBack, onJoinRoom }) {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [roomCode, setRoomCode] = useState('');

  const generateRoomCode = () => {
    return Math.random().toString(36).substring(2, 8).toUpperCase();
  };

  const handleCreateRoom = () => {
    if (!username.trim() || !password.trim()) {
      toast.error('Please enter both username and password');
      return;
    }

    const newRoomCode = generateRoomCode();
    setRoomCode(newRoomCode);
    
    // Store minimal data
    localStorage.setItem('user', JSON.stringify({ 
      username, 
      lastLogin: Date.now() 
    }));
    
    toast.success(`Room ${newRoomCode} created!`);
    setTimeout(() => {
      onJoinRoom(newRoomCode, username);
    }, 1500);
  };

  return (
    <div className="login-container">
      <div className="login-card">
        <div className="login-header">
          <button onClick={onBack} className="back-btn">
            <ArrowLeft size={20} />
          </button>
          <UserPlus className="login-logo" />
          <h1>Create Room</h1>
          <p>Start a new collaborative session</p>
        </div>

        <div className="login-form">
          <div className="input-group">
            <label>Username</label>
            <input
              type="text"
              placeholder="Enter your username"
              value={username}
              onChange={(e) => setUsername(e.target.value)}
              className="login-input"
              autoComplete="username"
            />
          </div>

          <div className="input-group">
            <label>Password (for this session)</label>
            <input
              type="password"
              placeholder="Enter session password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              className="login-input"
              autoComplete="new-password"
            />
          </div>

          <button onClick={handleCreateRoom} className="btn btn-create btn-large">
            <UserPlus size={18} />
            Create Room
          </button>

          {roomCode && (
            <div className="room-created">
              <p>Room Created Successfully!</p>
              <p>Room Code: <strong>{roomCode}</strong></p>
              <p className="share-hint">Share this code with your team members</p>
              <p className="joining-text">Joining room automatically...</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

// Join Room Component
function JoinRoom({ onBack, onJoinRoom }) {
  const [username, setUsername] = useState('');
  const [roomCode, setRoomCode] = useState('');

  const handleJoinRoom = () => {
    if (!username.trim() || !roomCode.trim()) {
      toast.error('Please fill all fields');
      return;
    }

    // Store minimal data
    localStorage.setItem('user', JSON.stringify({ 
      username, 
      lastLogin: Date.now() 
    }));

    onJoinRoom(roomCode.toUpperCase(), username);
  };

  return (
    <div className="login-container">
      <div className="login-card">
        <div className="login-header">
          <button onClick={onBack} className="back-btn">
            <ArrowLeft size={20} />
          </button>
          <LogIn className="login-logo" />
          <h1>Join Room</h1>
          <p>Enter an existing room code</p>
        </div>

        <div className="login-form">
          <div className="input-group">
            <label>Username</label>
            <input
              type="text"
              placeholder="Enter your username"
              value={username}
              onChange={(e) => setUsername(e.target.value)}
              className="login-input"
              autoComplete="username"
            />
          </div>

          <div className="input-group">
            <label>Room Code</label>
            <input
              type="text"
              placeholder="Enter room code (e.g., A1B2C3)"
              value={roomCode}
              onChange={(e) => setRoomCode(e.target.value.toUpperCase())}
              className="login-input"
            />
          </div>

          <button onClick={handleJoinRoom} className="btn btn-join btn-large">
            <LogIn size={18} />
            Join Room
          </button>
        </div>
      </div>
    </div>
  );
}

// Language Selector Component
function LanguageSelector({ currentLanguage, onLanguageChange }) {
  const [isOpen, setIsOpen] = useState(false);

  const currentLang = LANGUAGE_OPTIONS.find(lang => lang.id === currentLanguage) || LANGUAGE_OPTIONS[0];

  return (
    <div className="language-selector">
      <button 
        className="language-dropdown-btn"
        onClick={() => setIsOpen(!isOpen)}
      >
        <span>{currentLang.name}</span>
        <ChevronDown size={16} />
      </button>
      
      {isOpen && (
        <div className="language-dropdown">
          {LANGUAGE_OPTIONS.map((language) => (
            <button
              key={language.id}
              className={`language-option ${currentLanguage === language.id ? 'active' : ''}`}
              onClick={() => {
                onLanguageChange(language.id);
                setIsOpen(false);
              }}
            >
              {language.name}
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

// Terminal Component
function TerminalOutput({ output, onClear }) {
  return (
    <div className="terminal-section">
      <div className="section-header">
        <Terminal className="section-icon" />
        <h3>Terminal Output</h3>
        <div className="terminal-actions">
          <button onClick={onClear} className="btn btn-secondary btn-sm">
            Clear
          </button>
          <button 
            onClick={() => {
              navigator.clipboard.writeText(output);
              toast.success('Output copied!');
            }} 
            className="btn btn-secondary btn-sm"
          >
            <Copy size={12} />
          </button>
        </div>
      </div>
      <div className="terminal-output">
        <pre>{output || 'Run your code to see output here...'}</pre>
      </div>
    </div>
  );
}

// Main Editor Component
function EditorPage({ roomId, username, onLeaveRoom }) {
  const [code, setCode] = useState(DEFAULT_CODE.javascript);
  const [language, setLanguage] = useState('javascript');
  const [onlineUsers, setOnlineUsers] = useState([]);
  const [aiPrompt, setAiPrompt] = useState('');
  const [aiResponse, setAiResponse] = useState('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [showUsersPopup, setShowUsersPopup] = useState(false);
  const [documentVersion, setDocumentVersion] = useState(0);
  const [terminalOutput, setTerminalOutput] = useState('');
  const [isRunning, setIsRunning] = useState(false);
  const editorRef = useRef(null);

  // Clear cache on component mount
  useEffect(() => {
    // Clean up any old socket connections
    return () => {
      if (socket.connected) {
        socket.disconnect();
      }
    };
  }, []);

  useEffect(() => {
    // Join room when component mounts
    socket.emit('join-room', roomId, username);

    // Socket event listeners
    socket.on('connect', () => {
      console.log('Connected to server');
    });

    socket.on('document-state', (state) => {
      console.log('Received document state:', state);
      if (state.content !== undefined) {
        setCode(state.content);
      }
      if (state.language) {
        setLanguage(state.language);
      }
      if (state.version !== undefined) {
        setDocumentVersion(state.version);
      }
    });

    socket.on('code-update', (update) => {
      console.log('Received code update:', update);
      const { operation, content, version } = update;
      
      if (operation && editorRef.current) {
        OTUtils.applyOperationToEditor(editorRef.current, operation);
      }
      
      setCode(content);
      setDocumentVersion(version);
    });

    socket.on('users-update', (users) => {
      console.log('Users updated:', users);
      setOnlineUsers(users);
    });

    socket.on('user-joined', (userData) => {
      toast.info(`${userData.username} joined the room`);
    });

    socket.on('user-left', (userData) => {
      toast.warning(`${userData.username} left the room`);
    });

    socket.on('language-update', (newLanguage) => {
      setLanguage(newLanguage);
      toast.info(`Language changed to ${newLanguage}`);
    });

    socket.on('ai-completion', (completion) => {
      setAiResponse(completion);
      toast.success('AI completion ready!');
    });

    socket.on('code-analysis', (analysis) => {
      setAiResponse(analysis);
      setIsAnalyzing(false);
      toast.success('Code analysis complete!');
    });

    socket.on('sync-response', (operations, state) => {
      if (editorRef.current) {
        operations.forEach(op => {
          OTUtils.applyOperationToEditor(editorRef.current, op);
        });
      }
      if (state) {
        setCode(state.content);
        setDocumentVersion(state.version);
      }
      toast.info('Synced with latest version');
    });

    socket.on('error', (error) => {
      toast.error(error.message || 'An error occurred');
    });

    // Clean up on unmount
    return () => {
      socket.off('connect');
      socket.off('document-state');
      socket.off('code-update');
      socket.off('users-update');
      socket.off('user-joined');
      socket.off('user-left');
      socket.off('language-update');
      socket.off('ai-completion');
      socket.off('code-analysis');
      socket.off('sync-response');
      socket.off('error');
    };
  }, [roomId, username]);

  const handleEditorChange = (value, change) => {
    if (change && change.changes && change.changes.length > 0) {
      const monacoChange = change.changes[0];
      const operation = OTUtils.createOperationFromChange(monacoChange);
      
      if (operation) {
        socket.emit('code-change', operation, roomId);
      }
    }
    setCode(value);
  };

  const handleLanguageChange = (newLanguage) => {
    setLanguage(newLanguage);
    socket.emit('language-change', newLanguage, roomId);
  };

  const handleRunCode = async () => {
    if (!code.trim()) {
      toast.error('No code to run');
      return;
    }

    setIsRunning(true);
    setTerminalOutput('Running code...\n');

    try {
      const response = await axios.post('http://localhost:5000/api/execute', {
        code,
        language
      });

      if (response.data.success) {
        setTerminalOutput(prev => prev + '✅ Execution successful!\n' + response.data.output);
        toast.success('Code executed successfully!');
      } else {
        setTerminalOutput(prev => prev + '❌ Execution failed!\n' + response.data.output);
        toast.error('Code execution failed');
      }
    } catch (error) {
      setTerminalOutput(prev => prev + '❌ Error: ' + error.message);
      toast.error('Failed to execute code');
    } finally {
      setIsRunning(false);
    }
  };

  const handleAICompletion = () => {
    if (aiPrompt.trim()) {
      socket.emit('request-ai-completion', aiPrompt, code, language, roomId);
      toast.info(`AI is generating ${language} code...`);
      setAiPrompt('');
    }
  };

  const handleCodeAnalysis = () => {
    if (code.trim()) {
      setIsAnalyzing(true);
      socket.emit('request-code-analysis', code, language, roomId);
      toast.info(`Analyzing ${language} code...`);
    }
  };

  const applyAICompletion = () => {
    if (aiResponse && editorRef.current) {
      const position = editorRef.current.getPosition();
      const operation = {
        type: 'insert',
        position: editorRef.current.getModel().getOffsetAt(position),
        text: '\n' + aiResponse
      };
      socket.emit('code-change', operation, roomId);
      setAiResponse('');
      toast.success('AI completion applied!');
    }
  };

  const syncDocument = () => {
    socket.emit('sync-request', documentVersion, roomId);
  };

  const shareRoom = () => {
    navigator.clipboard.writeText(roomId);
    toast.success('Room ID copied to clipboard!');
  };

  const clearTerminal = () => {
    setTerminalOutput('');
  };

  const downloadCode = () => {
    const blob = new Blob([code], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `code-${roomId}-${language}.${LANGUAGE_OPTIONS.find(l => l.id === language)?.extension || 'txt'}`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
    toast.success('Code downloaded!');
  };

  const leaveRoom = () => {
    socket.disconnect();
    onLeaveRoom();
  };

  const currentLang = LANGUAGE_OPTIONS.find(lang => lang.id === language) || LANGUAGE_OPTIONS[0];

  return (
    <div className="app">
      <header className="app-header">
        <div className="header-left">
          <Code2 className="logo-icon" />
          <h1>Unified IDE</h1>
        </div>
        
        <div className="header-center">
          <div className="room-info">
            <span>Room: <strong>{roomId}</strong></span>
            <span className="user-info">as <strong>{username}</strong></span>
            <LanguageSelector 
              currentLanguage={language} 
              onLanguageChange={handleLanguageChange} 
            />
            <button onClick={syncDocument} className="btn btn-secondary btn-sm" title="Sync with latest version">
              <RefreshCw size={14} />
              Sync (v{documentVersion})
            </button>
            <button onClick={shareRoom} className="btn btn-secondary btn-sm">
              <Share2 size={14} />
              Share
            </button>
            <button onClick={downloadCode} className="btn btn-secondary btn-sm">
              <Download size={14} />
              Save
            </button>
            <button onClick={leaveRoom} className="btn btn-warning btn-sm">
              Leave Room
            </button>
          </div>
        </div>

        <div className="header-right">
          <div 
            className="online-users-toggle"
            onClick={() => setShowUsersPopup(!showUsersPopup)}
          >
            <Users size={18} />
            <span>{onlineUsers.length} online</span>
          </div>

          {showUsersPopup && (
            <div className="users-popup">
              <div className="popup-header">
                <h4>Online Users ({onlineUsers.length})</h4>
                <button 
                  onClick={() => setShowUsersPopup(false)}
                  className="close-btn"
                >
                  <X size={16} />
                </button>
              </div>
              <div className="popup-users-list">
                {onlineUsers.map((user, index) => (
                  <div key={user.id || index} className={`popup-user-item ${user.username === username ? 'current-user' : ''}`}>
                    <div className="user-avatar"></div>
                    <span>{user.username} {user.username === username && '(You)'}</span>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      </header>

      <div className="main-content">
        <div className="editor-container">
          <div className="editor-header">
            <h3>Collaborative Editor - {currentLang.name} • Real-time Sync Active</h3>
            <div className="editor-actions">
              <button onClick={handleRunCode} className="btn btn-success" disabled={isRunning}>
                <Play size={16} />
                {isRunning ? 'Running...' : `Run ${currentLang.name}`}
              </button>
              <button onClick={handleCodeAnalysis} className="btn btn-warning" disabled={isAnalyzing}>
                <AlertTriangle size={16} />
                {isAnalyzing ? 'Analyzing...' : 'Analyze Code'}
              </button>
            </div>
          </div>
          
          <Editor
            height="60vh"
            language={language}
            value={code}
            onChange={handleEditorChange}
            onMount={(editor) => {
              editorRef.current = editor;
              
              editor.onDidChangeCursorPosition((e) => {
                const position = editor.getModel().getOffsetAt(e.position);
                socket.emit('cursor-update', position, roomId);
              });
            }}
            theme="vs-dark"
            options={{
              minimap: { enabled: true },
              fontSize: 14,
              wordWrap: 'on',
              automaticLayout: true,
              scrollBeyondLastLine: false,
            }}
          />

          <TerminalOutput 
            output={terminalOutput} 
            onClear={clearTerminal}
          />
        </div>

        <div className="sidebar">
          <div className="ai-section">
            <div className="section-header">
              <Bot className="section-icon" />
              <h3>AI Assistant</h3>
              <Sparkles className="sparkle-icon" />
            </div>

            <div className="ai-input-group">
              <div className="language-badge">
                Currently editing: <strong>{currentLang.name}</strong>
              </div>
              <textarea
                placeholder={`Ask AI to generate ${currentLang.name} code, fix bugs, or explain concepts...`}
                value={aiPrompt}
                onChange={(e) => setAiPrompt(e.target.value)}
                className="ai-textarea"
                rows="3"
              />
              <button onClick={handleAICompletion} className="btn btn-ai">
                <Bot size={16} />
                Generate {currentLang.name} Code
              </button>
            </div>

            {aiResponse && (
              <div className="ai-response">
                <div className="response-header">
                  <h4>AI Response for {currentLang.name}</h4>
                  <button onClick={applyAICompletion} className="btn btn-success btn-sm">
                    <CheckCircle size={14} />
                    Apply
                  </button>
                </div>
                <pre className="response-content">{aiResponse}</pre>
              </div>
            )}
          </div>
        </div>
      </div>

      <ToastContainer
        position="bottom-right"
        autoClose={3000}
        hideProgressBar={false}
        newestOnTop
        closeOnClick
        rtl={false}
        pauseOnFocusLoss
        draggable
        pauseOnHover
      />
    </div>
  );
}

// Main App Component
function App() {
  const [currentView, setCurrentView] = useState('options');
  const [currentRoom, setCurrentRoom] = useState(null);
  const [currentUser, setCurrentUser] = useState(null);

  // Clear old cache on app start
  useEffect(() => {
    const userData = localStorage.getItem('user');
    if (userData) {
      const { lastLogin } = JSON.parse(userData);
      // Clear if last login was more than 1 hour ago
      if (Date.now() - lastLogin > 3600000) {
        localStorage.clear();
      }
    }
  }, []);

  const handleSelectOption = (option) => {
    setCurrentView(option);
  };

  const handleBack = () => {
    setCurrentView('options');
  };

  const handleJoinRoom = (roomId, username) => {
    setCurrentRoom(roomId);
    setCurrentUser(username);
    setCurrentView('editor');
  };

  const handleLeaveRoom = () => {
    if (socket.connected) {
      socket.disconnect();
    }
    setCurrentRoom(null);
    setCurrentUser(null);
    setCurrentView('options');
  };

  if (currentView === 'options') {
    return <LoginOptions onSelectOption={handleSelectOption} />;
  } else if (currentView === 'create') {
    return <CreateRoom onBack={handleBack} onJoinRoom={handleJoinRoom} />;
  } else if (currentView === 'join') {
    return <JoinRoom onBack={handleBack} onJoinRoom={handleJoinRoom} />;
  } else if (currentView === 'editor') {
    return (
      <EditorPage 
        roomId={currentRoom} 
        username={currentUser} 
        onLeaveRoom={handleLeaveRoom} 
      />
    );
  }
}

export default App;
